import pandas as pd
from sklearn.cluster import KMeans
import matplotlib.pyplot as plt
import seaborn as sns

# Load the dataset
wine_data = pd.read_csv('/content/wine.data')

# Get attributes and set as headers
headers = ['class','Alcohol','MalicAcid','Ash','AlcalinityOfAsh','Magnesium','TotalPhenols','Flavanoids','NonflavanoidPhenols',
           'Proanthocyanins','ColorIntensity','Hue','OD280_OD315','Proline']
wine_data.columns = headers

# Print the first few rows of the dataset
print(wine_data.head(3))

# Print summary statistics of the dataset
print(wine_data.describe())

############### EDA ###############
# Finding best features to analysis wine data
# To analyze the wine dataset effectively, it’s important to identify features that provide the most informative insights about the wine quality and types.

# Feature Correlation Analysis
# To identify which features are highly correlated and provide redundant information in our wine data anaysis, we carry out feature correlation analysis.
from sklearn.preprocessing import StandardScaler

# Let's assume all columns are the features that we interested to perform the analysis
features = wine_data[headers]

# Standardize the features using Z-score Normalization (Standardization), drop target column 'class'
scaler = StandardScaler()
features_scaled = scaler.fit_transform(wine_data.drop('class',axis=1))
target = wine_data['class']

# 1. Feature Correlation Analysis
#   Compute the correlation matrix
corr_matrix = wine_data.corr()

#   Plot the correlation matrix
plt.figure(figsize=(8, 6))
sns.heatmap(corr_matrix, annot=True, cmap='coolwarm', fmt='.2f')
plt.title('Feature Correlation Matrix')
plt.show()

# Remove Highly Correlated Features
import numpy as np

# Set threshold for correlation
threshold = 1.0 #0.9

# Find features to drop
features_to_drop = []
for i in range(len(corr_matrix.columns)):
    for j in range(i):
        if abs(corr_matrix.iloc[i, j]) > threshold:
            colname = corr_matrix.columns[i]
            features_to_drop.append(colname)

# Drop the features
features_to_drop = list(set(features_to_drop))
print("Features To Drop:", features_to_drop)

# As there are no highly correlated features in data, we use another method to find the best features.

# We use some feature selection techniques
# 1. Recursive Feature Elimination (RFE)
from sklearn.feature_selection import RFE
from sklearn.linear_model import LogisticRegression

# Initialize model
model = LogisticRegression(max_iter=1000)

# Initialize RFE
rfe = RFE(model, n_features_to_select=2)  # Select top 2 features
fit = rfe.fit(features_scaled, target)

# We take all columns except 'class' column in finding the best ranking features
features_to_be_selected = pd.DataFrame({'Feature': features.columns[1:14],
                                        'Support': fit.support_,
                                        'Ranking': fit.ranking_}).sort_values(by='Ranking')

print("Features To Be Selected:\n",features_to_be_selected)

# Now we select the best features
selected_features = features_to_be_selected[features_to_be_selected['Support']==True]
print("\nSelected features:\n",selected_features)

############### CLUSTERING ###############
# Now we perform clustering on the selected features.
import matplotlib.pyplot as plt
from sklearn.cluster import KMeans

# Define a function to create a plot with different cluster
def PlotChartByCluster(n_cluster):
    # Fit a model KMeans to the data
    model = KMeans(n_clusters=n_cluster, random_state=42)

    # Get the clusters
    X = wine_data[selected_features['Feature']]
    clusters = model.fit_predict(X)

    # Get the cluster center
    cluster_centers  = model.cluster_centers_

    # Visualize the result by generating the scatter plot
    plt.figure(figsize=(5, 15))
    plt.subplot(5, 1, n_cluster - 1)
    plt.scatter( X[X.columns[0]], X[X.columns[1]], c= clusters , s=30, cmap='viridis')
    plt.scatter(cluster_centers [:,0], cluster_centers [:,1], c='red', s=100, alpha=0.5)
    plt.title(f"Scatter Plot With {n_cluster} Clusters")
    plt.show()

# Define the range of k values to test
range_n_clusters = range(2,7)

# Loop through the range of k values
for n_cluster in range_n_clusters:
    PlotChartByCluster(n_cluster)


############### DETERMINING THE BEST POSSIBLE VALUE OF K ###############

# We have tried clustering with different possible values of k
# Now we will try to get better-defined clusters by finding higher Silhouette Coefficient score.

from sklearn.metrics import silhouette_score

# Initialize a list to store the average silhouette scores
silhouette_avg_scores = []

# Loop through the range of K values
for n_cluster in range_n_clusters:
  X = wine_data[selected_features['Feature']]
  kmeans = KMeans(n_clusters=n_cluster).fit(X)
  label = kmeans.labels_
  sil_coeff = silhouette_score(X, label, metric='euclidean')
  print(f"For n_cluster={n_cluster}, The Silhouette Coefficient is {sil_coeff}.")

  # Append the average silhouette score to the list
  silhouette_avg_scores.append(kmeans.inertia_)

# Plot the silhouette scores
plt.figure()
plt.plot(range_n_clusters, silhouette_avg_scores, marker='o')
plt.xlabel('Number of clusters (K)')
plt.ylabel('Average Silhouette Score')
plt.title('Silhouette Scores for Different K Values')
plt.show()

# Elbow Method
Sum_of_squared_distances = []
for cluster in range_n_clusters :
    kmeans = KMeans(n_clusters=cluster).fit(X)
    Sum_of_squared_distances.append(kmeans.inertia_)

plt.plot(range_n_clusters,Sum_of_squared_distances, "bx-")
plt.xlabel("Values of K")
plt.ylabel("Sum of squared distances/Inertia")
plt.title("Elbow Method For Optimal k")
plt.show()

# As the plot using Elbow method shown, we can understand that getting the best-defined clusters would be able to achieve by using the best optimal k value of 3.


############### DBSCAN CLUSTERING ALGORITHM ###############

# Now we try other possible clustering algorithms

# 1. DBSCAN Clustering
# Unlike k-means clustering, DBSCAN algorithm that groups together points that are closely packed together,
# while marking points that lie alone in low-density regions as outliers.
# So we need to find the minimum number of points(=min_samples) required to form a dense region (i.e., a cluster)
# and the maximum distance between two points for them to be considered as part of the same neighborhood which is known as 'eps' in DBSCAN algorithm.

# We compute the k-distance for each point (commonly used k is min_samples - 1)
# Let's assume min_samples is 3, so k is 2

from sklearn.neighbors import NearestNeighbors
from sklearn.cluster import DBSCAN

k = 2
X = wine_data[selected_features['Feature']]
NNLearner = NearestNeighbors(n_neighbors=k)
NNModel = NNLearner.fit(X)
distances, indices = NNModel.kneighbors(X)

# Sort the distances and plot
distances = np.sort(distances, axis=0)
distances = distances[:,1]
plt.plot(distances)
plt.ylabel("k-distance")
plt.xlabel("Data Points sorted by distance")
plt.title("k-Distance Graph for DBSCAN")
plt.show()



# The optimal value for epsilon will be found at the point of maximum curvature which is around from 0.4 to 0.6
# We take epsilon value as 0.5

eps = 0.5
min_samples = 3

# Apply DBSCAN
dbscan = DBSCAN(eps=0.5, min_samples=3)
dbscan_clusters = dbscan.fit_predict(wine_data[selected_features['Feature']])

print('dbscan clusters= \n', dbscan_clusters)

# Add clusters to DataFrame
wine_data['DBSCAN_Cluster'] = dbscan_clusters

labels = dbscan.labels_
# Number of clusters in labels, ignoring noise if present.
n_clusters_ = len(set(labels)) - (1 if -1 in labels else 0)
n_noise_ = list(labels).count(-1)

print("Estimated number of clusters: %d" % n_clusters_)
print("Estimated number of noise points: %d" % n_noise_)

# Plot the results
sns.pairplot(X.assign(Cluster=dbscan_clusters), hue='Cluster', palette='viridis',plot_kws={'alpha': 0.6})
plt.suptitle('DBSCAN Clustering Pair Plot', y=1.02)
plt.show()



